const groqResponse = $input.item.json;
  const candidate = $('Validate Required Fields').item.json;

  let scoring;
  try {
    const rawContent = groqResponse.choices[0].message.content;
    scoring = JSON.parse(rawContent);
  } catch (e) {
    return {
      json: {
        name: candidate.name ?? '(unknown)',
        email: candidate.email ?? '',
        location: candidate.location ?? '',
        years_experience: candidate.years_experience ?? '',
        current_role: candidate.current_role ?? '',
        ats_experience: candidate.ats_experience ?? '',
        ashby_score: 'ERROR', coordination_score: 'ERROR',
        english_score: 'ERROR', startup_score: 'ERROR',
        automation_score: 'ERROR', overall_score: 'ERROR',
        tier: 'ERROR',
        top_strengths: '',
        main_gap: 'LLM parsing failed',
        recommendation: `Parse error: ${e.message}`,
        scored_at: new Date().toISOString(),
      }
    };
  }

  const required = ['ashby_score','coordination_score','english_score','startup_score','automation_score'];
  const missing = required.filter(k => scoring[k] == null);
  if (missing.length > 0) {
    return {
      json: {
        name: candidate.name ?? '(unknown)',
        email: candidate.email ?? '',
        location: candidate.location ?? '',
        years_experience: candidate.years_experience ?? '',
        current_role: candidate.current_role ?? '',
        ats_experience: candidate.ats_experience ?? '',
        ashby_score: 'ERROR', coordination_score: 'ERROR',
        english_score: 'ERROR', startup_score: 'ERROR',
        automation_score: 'ERROR', overall_score: 'ERROR',
        tier: 'ERROR',
        top_strengths: '',
        main_gap: `Missing fields: ${missing.join(', ')}`,
        recommendation: 'Manual review required.',
        scored_at: new Date().toISOString(),
      }
    };
  }

  const recomputed = Math.round((
    Number(scoring.ashby_score)        * 0.30 +
    Number(scoring.coordination_score) * 0.25 +
    Number(scoring.english_score)      * 0.20 +
    Number(scoring.startup_score)      * 0.15 +
    Number(scoring.automation_score)   * 0.10
  ) * 10) / 10;

  const tier = recomputed >= 7.5 ? 'Strong Yes'
             : recomputed >= 6.0 ? 'Yes'
             : recomputed >= 4.5 ? 'Maybe'
             : 'No';

  return {
    json: {
      name: candidate.name,
      email: candidate.email,
      location: candidate.location,
      years_experience: candidate.years_experience,
      current_role: candidate.current_role,
      ats_experience: candidate.ats_experience,
      ashby_score: scoring.ashby_score,
      coordination_score: scoring.coordination_score,
      english_score: scoring.english_score,
      startup_score: scoring.startup_score,
      automation_score: scoring.automation_score,
      overall_score: recomputed,
      tier,
      top_strengths: scoring.top_strengths ?? '',
      main_gap: scoring.main_gap ?? '',
      recommendation: scoring.recommendation ?? '',
      scored_at: new Date().toISOString(),
    }
  };
